 {"id":"remote_compilation_helper-dyr","title":"Task: Unit Tests for SpeedScore Calculation","description":"## Overview
Implement comprehensive unit tests for the SpeedScore calculation engine, focusing on normalization, weighting, and edge case handling.

## Background and Justification
SpeedScore is the single metric users see for worker performance. Incorrect calculations lead to wrong worker selection. Tests must verify:
- Normalization maps correctly to 0-100 range
- Weights are applied correctly
- Edge cases produce sensible results
- Score comparisons are valid

## Test Categories

### 1. Normalization Tests
```rust
#[cfg(test)]
mod normalization_tests {
    use super::*;

    #[test]
    fn test_normalize_at_low_reference() {
        // Value at low reference should score 0
        let score = normalize(10.0, 10.0, 500.0, true);
        assert_eq!(score, 0.0);
    }

    #[test]
    fn test_normalize_at_high_reference() {
        // Value at high reference should score 100
        let score = normalize(500.0, 10.0, 500.0, true);
        assert_eq!(score, 100.0);
    }

    #[test]
    fn test_normalize_midpoint() {
        // Midpoint between references
        let score = normalize(255.0, 10.0, 500.0, true);
        assert!((score - 50.0).abs() < 0.1);
    }

    #[test]
    fn test_normalize_below_low_reference() {
        // Below low reference clamps to 0
        let score = normalize(5.0, 10.0, 500.0, true);
        assert_eq!(score, 0.0);
    }

    #[test]
    fn test_normalize_above_high_reference() {
        // Above high reference clamps to 100
        let score = normalize(1000.0, 10.0, 500.0, true);
        assert_eq!(score, 100.0);
    }

    #[test]
    fn test_normalize_lower_is_better() {
        // For latency, lower values are better
        let score = normalize(1.0, 100.0, 1.0, false);  // low=bad, high=good
        assert_eq!(score, 100.0);  // 1ms latency = perfect
    }

    #[test]
    fn test_normalize_negative_values() {
        // Should handle gracefully
        let score = normalize(-10.0, 10.0, 500.0, true);
        assert_eq!(score, 0.0);
    }

    #[test]
    fn test_normalize_nan() {
        // NaN input should return 0 or error
        let score = normalize(f64::NAN, 10.0, 500.0, true);
        assert_eq!(score, 0.0);  // or assert!(score.is_nan());
    }
}
```

### 2. Weight Application Tests
```rust
#[cfg(test)]
mod weight_tests {
    #[test]
    fn test_weights_sum_to_one() {
        let weights = SpeedScoreWeights::default();
        let sum = weights.cpu + weights.memory + weights.disk + 
                  weights.network + weights.compilation;
        assert!((sum - 1.0).abs() < 0.001);
    }

    #[test]
    fn test_all_perfect_scores() {
        let results = BenchmarkResults {
            cpu: CpuResult { gflops: 500.0 },  // Perfect
            memory: MemoryResult { bandwidth_gbps: 100.0 },  // Perfect
            disk: DiskResult { sequential_read_mbps: 5000.0, random_read_iops: 500000 },
            network: NetworkResult { download_mbps: 10000.0, upload_mbps: 10000.0, ... },
            compilation: CompilationResult { units_per_sec: 200.0 },
        };

        let score = SpeedScore::calculate(&results, &SpeedScoreWeights::default());
        assert_eq!(score.total, 100.0);
    }

    #[test]
    fn test_all_poor_scores() {
        let results = BenchmarkResults {
            cpu: CpuResult { gflops: 10.0 },  // Minimum
            memory: MemoryResult { bandwidth_gbps: 5.0 },
            disk: DiskResult { sequential_read_mbps: 100.0, random_read_iops: 1000 },
            network: NetworkResult { download_mbps: 100.0, ... },
            compilation: CompilationResult { units_per_sec: 10.0 },
        };

        let score = SpeedScore::calculate(&results, &SpeedScoreWeights::default());
        assert_eq!(score.total, 0.0);
    }

    #[test]
    fn test_mixed_scores_weighted() {
        // CPU perfect, others poor - total should be weighted
        let results = BenchmarkResults {
            cpu: CpuResult { gflops: 500.0 },  // 100
            memory: MemoryResult { bandwidth_gbps: 5.0 },  // 0
            disk: DiskResult { sequential_read_mbps: 100.0, random_read_iops: 1000 },  // 0
            network: NetworkResult { download_mbps: 100.0, ... },  // 0
            compilation: CompilationResult { units_per_sec: 10.0 },  // 0
        };

        let weights = SpeedScoreWeights::default();
        let score = SpeedScore::calculate(&results, &weights);

        // Should be approximately CPU weight * 100
        assert!((score.total - weights.cpu * 100.0).abs() < 0.1);
    }

    #[test]
    fn test_custom_weights() {
        let custom_weights = SpeedScoreWeights {
            cpu: 0.50,
            memory: 0.10,
            disk: 0.10,
            network: 0.10,
            compilation: 0.20,
        };

        // Verify custom weights are respected
        let results = create_uniform_results(50.0);  // All components score 50
        let score = SpeedScore::calculate(&results, &custom_weights);
        assert_eq!(score.total, 50.0);  // Weighted average of 50s
    }
}
