### 3. Edge Case Tests
```rust
#[cfg(test)]
mod edge_case_tests {
    #[test]
    fn test_missing_cpu_benchmark() {
        let mut results = BenchmarkResults::default();
        results.cpu = None;  // Missing

        let score = SpeedScore::calculate(&results, &SpeedScoreWeights::default());
        // Should use neutral score (50) for missing component
        assert!(score.cpu_score == 50.0 || score.cpu_score.is_nan());
    }

    #[test]
    fn test_all_missing_benchmarks() {
        let results = BenchmarkResults::empty();
        let score = SpeedScore::calculate(&results, &SpeedScoreWeights::default());

        // Should return neutral overall score
        assert_eq!(score.total, 50.0);
    }

    #[test]
    fn test_extreme_values() {
        let results = BenchmarkResults {
            cpu: CpuResult { gflops: 1_000_000.0 },  // Ridiculously high
            ..Default::default()
        };

        let score = SpeedScore::calculate(&results, &SpeedScoreWeights::default());
        // Should clamp, not overflow
        assert!(score.cpu_score <= 100.0);
        assert!(!score.total.is_infinite());
    }

    #[test]
    fn test_zero_weight_component() {
        let weights = SpeedScoreWeights {
            cpu: 0.0,  // Zero weight
            memory: 0.25,
            disk: 0.25,
            network: 0.25,
            compilation: 0.25,
        };

        // CPU score shouldn't affect total
        let mut results = create_uniform_results(50.0);
        results.cpu.gflops = 500.0;  // Perfect CPU

        let score = SpeedScore::calculate(&results, &weights);
        assert_eq!(score.total, 50.0);  // CPU ignored
    }
}
```

