            ..Default::default()
        };

        let score = SpeedScore::calculate(&results, &SpeedScoreWeights::default());

        prop_assert!(score.total >= 0.0);
        prop_assert!(score.total <= 100.0);
        prop_assert!(score.cpu_score >= 0.0);
        prop_assert!(score.cpu_score <= 100.0);
    }

    #[test]
    fn normalization_is_monotonic(a in 0.0f64..1000.0, b in 0.0f64..1000.0) {
        let score_a = normalize(a, 10.0, 500.0, true);
        let score_b = normalize(b, 10.0, 500.0, true);

        if a > b {
            prop_assert!(score_a >= score_b);
        } else {
            prop_assert!(score_a <= score_b);
        }
    }
}
